const babelTypes = require('@babel/types');

/**
 * Detects exports of type "export function fnName() {}"
 * @param {babel.NodePath<babelTypes.ExportNamedDeclaration>} babelPath
 */
const isFunctionExpressionNamedExport = (babelPath) =>
  babelTypes.isFunctionDeclaration(babelPath.node.declaration) &&
  babelTypes.isIdentifier(babelPath.node.declaration?.id);

/**
 * Detects exports of type "export const exportIdentifier = ..." or "export const {...} = ..."
 * @param {babel.NodePath<babelTypes.ExportNamedDeclaration>} babelPath
 */
const isVariableNamedExport = (babelPath) =>
  babelTypes.isVariableDeclaration(babelPath.node.declaration);

/**
 * Detects exports of type "export { namedExport };" or "export { namedExport as exportName };" or "export {...} from 'path';"
 * @param {babel.NodePath<babelTypes.ExportNamedDeclaration>} babelPath
 */
const isObjectExport = (babelPath) => !!babelPath.node.specifiers?.length;

/**
 * Detects exports of type "export default exportIdentifier;"
 * @param {babel.NodePath<babelTypes.ExportDefaultDeclaration>} babelPath
 */
const isIdentifierDefaultExport = (babelPath) =>
  babelTypes.isIdentifier(babelPath.node.declaration);

/**
 * Detects exports of type "export default {...};"
 * @param {babel.NodePath<babelTypes.ExportDefaultDeclaration>} babelPath
 */
const isObjectDefaultExport = (babelPath) =>
  babelTypes.isObjectExpression(babelPath.node.declaration) &&
  !!babelPath.node.declaration.properties.length;

/**
 * Detects exports of type "export default (...) => {...};" or "export default function (...) {...}"
 * @param {babel.NodePath<babelTypes.ExportDefaultDeclaration>} babelPath
 */
const isFunctionDefaultExport = (babelPath) =>
  babelTypes.isArrowFunctionExpression(babelPath.node.declaration) ||
  babelTypes.isFunctionDeclaration(babelPath.node.declaration);

/**
 * Detects exports of type "class ClassName extends Superclass { render(){...} }"
 * @param {babel.NodePath<babelTypes.ClassDeclaration>} babelPath
 */
const isPotencialReactClassDeclaration = (babelPath) =>
  !!babelPath.node.superClass &&
  !!babelPath.node.body.body.find(
    (bodyItem) =>
      babelTypes.isMethod(bodyItem) &&
      babelTypes.isIdentifier(bodyItem.key) &&
      bodyItem.key.name === 'render',
  );

/**
 * Detects exports of type "export class ClassName extends Superclass { render(){...} }"
 * @param {babel.NodePath<babelTypes.ClassDeclaration>} babelPath
 */
const isPotencialReactClassNamedExport = (babelPath) =>
  isPotencialReactClassDeclaration(babelPath) &&
  babelTypes.isExportNamedDeclaration(babelPath.parent);

/**
 * Detects exports of type "export default class ClassName extends Superclass { render(){...} }"
 * @param {babel.NodePath<babelTypes.ClassDeclaration>} babelPath
 */
const isPotencialReactClassDefaultExport = (babelPath) =>
  isPotencialReactClassDeclaration(babelPath) &&
  babelTypes.isExportDefaultDeclaration(babelPath.parent);

module.exports = {
  isFunctionExpressionNamedExport,
  isVariableNamedExport,
  isObjectExport,
  isIdentifierDefaultExport,
  isObjectDefaultExport,
  isFunctionDefaultExport,
  isPotencialReactClassDeclaration,
  isPotencialReactClassDefaultExport,
  isPotencialReactClassNamedExport,
};
